const { PDFDocument, rgb, StandardFonts } = require('pdf-lib');
const nodemailer = require('nodemailer');
const fs = require('fs');
const path = require('path');

// ── logo (embedded at build time) ────────────────────────────────────────────
const LOGO_B64 = '';

async function buildPDF(data) {
  const pdfDoc = await PDFDocument.create();
  const page = pdfDoc.addPage([595, 842]);
  const { width, height } = page.getSize();

  const fontBold = await pdfDoc.embedFont(StandardFonts.HelveticaBold);
  const fontReg  = await pdfDoc.embedFont(StandardFonts.Helvetica);

  let y = height - 30;

  // ── header with logo ────────────────────────────────────────────────────
  try {
    const logoBytes = Buffer.from(LOGO_B64, 'base64');
    const logoImg   = await pdfDoc.embedJpg(logoBytes);
    const logoDims  = logoImg.scaleToFit(80, 50);
    page.drawImage(logoImg, { x: 40, y: y - logoDims.height, width: logoDims.width, height: logoDims.height });
  } catch(e) {
    // logo embed failed — draw text fallback
    page.drawText('tef', { x: 40, y, font: fontBold, size: 28, color: rgb(0.18, 0.45, 0.71) });
  }

  page.drawText('LE FRANÇAIS DES AFFAIRES', { x: 300, y, font: fontBold, size: 10, color: rgb(0.18, 0.45, 0.71) });
  y -= 14;
  page.drawText("TEST D'ÉVALUATION DE FRANÇAIS", { x: 150, y, font: fontReg, size: 9, color: rgb(0.4, 0.4, 0.4) });
  page.drawText('FRENCH FOR BUSINESS', { x: 300, y, font: fontReg, size: 9, color: rgb(0.4, 0.4, 0.4) });
  y -= 8;
  page.drawLine({ start: { x: 40, y }, end: { x: width - 40, y }, thickness: 0.5, color: rgb(0.8, 0.8, 0.8) });
  y -= 20;

  // ── main title ────────────────────────────────────────────────────────────
  const title = "Fiche d'inscription simplifiée";
  const titleW = fontBold.widthOfTextAtSize(title, 16);
  page.drawText(title, { x: (width - titleW) / 2, y, font: fontBold, size: 16, color: rgb(0.18, 0.45, 0.71) });
  y -= 20;

  page.drawText('Date de la session : ' + (data.session_date || '___/___/______'), {
    x: 40, y, font: fontReg, size: 10, color: rgb(0.2, 0.2, 0.2)
  });
  y -= 20;

  // ── helpers ───────────────────────────────────────────────────────────────
  function sectionBar(label) {
    page.drawRectangle({ x: 40, y: y - 4, width: width - 80, height: 16, color: rgb(0.29, 0.21, 0.50) });
    page.drawText(label, { x: 48, y: y - 1, font: fontBold, size: 10, color: rgb(1, 1, 1) });
    y -= 22;
  }

  function field(label, value, x, w) {
    page.drawText(label + ' :', { x, y, font: fontBold, size: 8, color: rgb(0.4, 0.4, 0.4) });
    page.drawText(value || '', { x, y: y - 11, font: fontReg, size: 10, color: rgb(0.1, 0.1, 0.1) });
    page.drawLine({ start: { x, y: y - 13 }, end: { x: x + w, y: y - 13 }, thickness: 0.4, color: rgb(0.7, 0.7, 0.7) });
  }

  // ── exam choices ──────────────────────────────────────────────────────────
  sectionBar('Choix du test');

  const cols = [
    { label: 'TEF',             key: 'tef',            items: ['comprehension_ecrite','comprehension_orale','lexique_structure','expression_ecrite','expression_orale'] },
    { label: 'TEFAQ',           key: 'tefaq',          items: ['comprehension_ecrite','comprehension_orale','expression_ecrite','expression_orale'] },
    { label: 'TEF Canada',      key: 'tefcanada',      items: ['comprehension_ecrite','comprehension_orale','expression_ecrite','expression_orale'] },
    { label: 'TEF Intégration', key: 'tefintegration', items: ['all'] },
  ];
  const labels = {
    comprehension_ecrite: 'Compréhension écrite',
    comprehension_orale:  'Compréhension orale',
    lexique_structure:    'Lexique / structure',
    expression_ecrite:    'Expression écrite',
    expression_orale:     'Expression orale',
    all:                  'Toutes épreuves',
  };
  const colW   = (width - 80) / 4;
  const examY  = y;

  cols.forEach((col, ci) => {
    const cx = 40 + ci * colW;
    let iy = examY;
    page.drawText(col.label, { x: cx, y: iy, font: fontBold, size: 9, color: rgb(0.18, 0.45, 0.71) });
    iy -= 13;
    const selected = Array.isArray(data[col.key]) ? data[col.key] : (data[col.key] ? [data[col.key]] : []);
    col.items.forEach(item => {
      const tick = selected.includes(item) ? '[X]' : '[ ]';
      page.drawText(tick + ' ' + (labels[item] || item), { x: cx, y: iy, font: fontReg, size: 8, color: rgb(0.2, 0.2, 0.2) });
      iy -= 12;
    });
  });
  y = examY - 13 - 5 * 12 - 10;

  // ── état civil ────────────────────────────────────────────────────────────
  sectionBar('État civil');
  ['Madame','Monsieur','Non-binaire'].forEach((c, i) => {
    const tick = data.civilite === c ? '(*)' : '( )';
    page.drawText(tick + ' ' + c, { x: 40 + i * 100, y, font: fontReg, size: 10, color: rgb(0.2, 0.2, 0.2) });
  });
  y -= 20;

  field('Numéro de passeport / carte identité', data.passport_id, 40, width - 80);
  y -= 26;
  field('Nom', data.nom, 40, 230);
  field('Prénom', data.prenom, 290, 265);
  y -= 26;
  field('Date de naissance', data.date_naissance, 40, 160);
  field('Pays de la nationalité', data.pays_nationalite, 220, 180);
  field('Langue maternelle', data.langue_maternelle, 420, width - 460);
  y -= 26;
  field('Adresse', data.adresse, 40, width - 80);
  y -= 26;
  field('Code postal', data.code_postal, 40, 100);
  field('Ville', data.ville, 160, 160);
  field('Pays', data.pays, 340, 110);
  field('Téléphone', data.telephone, 460, width - 500);
  y -= 26;
  field('Email', data.email, 40, width - 80);
  y -= 26;

  // ── motivation ────────────────────────────────────────────────────────────
  sectionBar('Motivation');
  const motivItems = [
    ['professionnelle',         'Professionnelle'],
    ['immigration_canada',      'Immigration au Canada'],
    ['nationalite_francaise',   'Accès à la nationalité française'],
    ['individuelle',            'Individuelle'],
    ['immigration_quebec',      'Immigration au Québec'],
    ['resident_france',         'Carte de résident en France'],
    ['citoyennete_canadienne',  "Accès à la citoyenneté canadienne"],
    ['integration_republicaine',"Contrat d'intégration républicaine"],
    ['etudes_france',           'Études en France'],
    ['academique',              'Académique'],
  ];
  const selectedMotiv = Array.isArray(data.motivation) ? data.motivation : (data.motivation ? [data.motivation] : []);
  const motivColW = (width - 80) / 3;
  motivItems.forEach(([val, label], i) => {
    const col = i % 3;
    const row = Math.floor(i / 3);
    const tick = selectedMotiv.includes(val) ? '[X]' : '[ ]';
    page.drawText(tick + ' ' + label, {
      x: 40 + col * motivColW,
      y: y - row * 14,
      font: fontReg, size: 9, color: rgb(0.2, 0.2, 0.2)
    });
  });
  y -= Math.ceil(motivItems.length / 3) * 14 + 10;

  // ── règlement ─────────────────────────────────────────────────────────────
  sectionBar('Règlement');
  field("Montant de l'inscription", data.montant ? data.montant + ' €' : '', 40, 150);
  y -= 26;
  ['cheque:Chèque','carte_credit:Carte de crédit','especes:Espèces'].forEach((p, i) => {
    const [val, label] = p.split(':');
    const tick = data.paiement === val ? '(*)' : '( )';
    page.drawText(tick + ' ' + label, { x: 40 + i * 130, y, font: fontReg, size: 10, color: rgb(0.2, 0.2, 0.2) });
  });
  y -= 20;
  page.drawText('[X] Certifie avoir pris connaissance des conditions et les accepter.', { x: 40, y, font: fontReg, size: 8, color: rgb(0.4,0.4,0.4) });
  y -= 12;
  page.drawText("[X] Certifie sur l'honneur l'exactitude des renseignements fournis.", { x: 40, y, font: fontReg, size: 8, color: rgb(0.4,0.4,0.4) });
  y -= 24;

  field('Signé à', data.signe_a, 40, 180);
  field('Le', data.signe_le, 240, 130);
  field('Signature', data.signature, 390, width - 430);

  // ── footer ────────────────────────────────────────────────────────────────
  page.drawLine({ start: { x: 40, y: 30 }, end: { x: width - 40, y: 30 }, thickness: 0.4, color: rgb(0.8,0.8,0.8) });
  page.drawText('www.lefrancaisdaffaires.fr  |  tef@mlicanada.ca', {
    x: 40, y: 18, font: fontReg, size: 8, color: rgb(0.5,0.5,0.5)
  });

  return await pdfDoc.save();
}

// ── main handler ──────────────────────────────────────────────────────────────
module.exports = async (req, res) => {
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });

  try {
    const data = req.body;

    const pdfBytes  = await buildPDF(data);
    const pdfBuffer = Buffer.from(pdfBytes);

    const transporter = nodemailer.createTransport({
      host: process.env.SMTP_HOST,
      port: parseInt(process.env.SMTP_PORT || '587'),
      secure: false,
      auth: {
        user: process.env.SMTP_USER,
        pass: process.env.SMTP_PASS,
      },
    });

    const studentName = `${data.prenom || ''} ${data.nom || ''}`.trim() || 'Étudiant';
    const filename    = `inscription_TEF_${(data.nom || 'candidat').replace(/\s+/g,'_')}.pdf`;

    // ── email to admin (fixed: tef@mlicanada.ca) ─────────────────────────
    await transporter.sendMail({
      from:    `"TEF Maison Alpha" <${process.env.SMTP_USER}>`,
      to:      'tef@mlicanada.ca',
      subject: `Nouvelle inscription TEF — ${studentName}`,
      html: `
        <h2>Nouvelle fiche d'inscription reçue</h2>
        <table style="font-family:sans-serif;font-size:14px;border-collapse:collapse">
          <tr><td style="padding:4px 12px 4px 0;color:#666">Nom</td><td><b>${data.nom} ${data.prenom}</b></td></tr>
          <tr><td style="padding:4px 12px 4px 0;color:#666">Email</td><td>${data.email}</td></tr>
          <tr><td style="padding:4px 12px 4px 0;color:#666">Téléphone</td><td>${data.telephone}</td></tr>
          <tr><td style="padding:4px 12px 4px 0;color:#666">Date session</td><td>${data.session_date || 'non précisée'}</td></tr>
        </table>
        <p style="color:#888;font-size:12px">La fiche complète est en pièce jointe (PDF).</p>
      `,
      attachments: [{ filename, content: pdfBuffer, contentType: 'application/pdf' }],
    });

    // ── confirmation to student ───────────────────────────────────────────
    if (data.email) {
      await transporter.sendMail({
        from:    `"TEF Maison Alpha" <${process.env.SMTP_USER}>`,
        to:      data.email,
        subject: `Confirmation d'inscription TEF — ${studentName}`,
        html: `
          <h2>Bonjour ${data.prenom || ''},</h2>
          <p>Nous avons bien reçu votre fiche d'inscription au TEF.</p>
          <p>Votre fiche est en pièce jointe. Conservez-la pour vos archives.</p>
          <br>
          <p>Pour toute question : <a href="mailto:tef@mlicanada.ca">tef@mlicanada.ca</a></p>
          <p style="color:#888;font-size:12px">Maison Alpha — TEF Canada</p>
        `,
        attachments: [{ filename, content: pdfBuffer, contentType: 'application/pdf' }],
      });
    }

    res.status(200).json({ success: true, message: 'Inscription envoyée avec succès !' });

  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Erreur serveur : ' + err.message });
  }
};
